import java.util.*;

class Solution {
    // Function to count subarrays with exactly K distinct integers
    public int subarraysWithKDistinct(int[] nums, int k) {
        // Store the total count of valid subarrays
        int count = 0;

        // Iterate through all possible starting points
        for (int i = 0; i < nums.length; i++) {

            // Use a hashmap to store frequency of elements
            Map<Integer, Integer> map = new HashMap<>();

            // Iterate through all possible end points
            for (int j = i; j < nums.length; j++) {

                // Update the frequency of the current number
                map.put(nums[j], map.getOrDefault(nums[j], 0) + 1);

                // If size equals k, it's a valid subarray
                if (map.size() == k)
                    count++;

                // If more than k distinct, break early
                if (map.size() > k)
                    break;
            }
        }

        // Return total valid subarrays
        return count;
    }
}

// Driver class
class Main {
    public static void main(String[] args) {
        Solution sol = new Solution();
        int[] nums = {1, 2, 1, 2, 3};
        int k = 2;
        System.out.println(sol.subarraysWithKDistinct(nums, k));
    }
}

